import type { Kayit } from '../../types';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell } from 'recharts';

interface CiroChartProps {
  records: Kayit[];
}

export default function CiroChart({ records }: CiroChartProps) {
  // Data processing: Aggregate total turnover by branch
  const dataMap = records.reduce((acc, record) => {
    const sube = record.sube_adi;
    acc[sube] = (acc[sube] || 0) + Number(record.tutar);
    return acc;
  }, {} as Record<string, number>);

  const data = Object.entries(dataMap).map(([name, value]) => ({
    name,
    value,
  })).sort((a, b) => b.value - a.value);

  const colors = ['#6366f1', '#8b5cf6', '#a855f7', '#d946ef', '#ec4899', '#f43f5e', '#f97316'];

  return (
    <div className="glassmorphism p-6 rounded-2xl shadow-lg border border-border/50 min-h-[450px] flex flex-col">
      <div className="flex justify-between items-center mb-6">
        <div>
          <h3 className="text-lg font-bold text-foreground">Şube Bazlı Ciro Dağılımı</h3>
          <p className="text-xs text-muted-foreground mt-1">Hangi şube ne kadar toplam tahsilat yaptı?</p>
        </div>
      </div>

      <div className="flex-1 w-full min-h-[300px]">
        <ResponsiveContainer width="99%" height="100%" minHeight={300}>
          <BarChart data={data} margin={{ top: 20, right: 30, left: 20, bottom: 60 }}>
            <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="rgba(255,255,255,0.05)" />
            <XAxis 
              dataKey="name" 
              axisLine={false}
              tickLine={false}
              tick={{ fill: '#94a3b8', fontSize: 12 }}
              angle={-45}
              textAnchor="end"
              interval={0}
            />
            <YAxis 
              axisLine={false}
              tickLine={false}
              tick={{ fill: '#94a3b8', fontSize: 12 }}
              tickFormatter={(value) => `${value / 1000}k`}
            />
            <Tooltip
              cursor={{ fill: 'rgba(255,255,255,0.05)' }}
              contentStyle={{
                backgroundColor: 'rgba(15, 23, 42, 0.9)',
                border: '1px solid rgba(255,255,255,0.1)',
                borderRadius: '12px',
                color: '#fff'
              }}
              itemStyle={{ color: '#6366f1' }}
              formatter={(value: any) => [`${new Intl.NumberFormat('tr-TR').format(Number(value))} TL`, 'Ciro']}
            />
            <Bar dataKey="value" radius={[6, 6, 0, 0]} barSize={40}>
              {data.map((_, index) => (
                <Cell key={`cell-${index}`} fill={colors[index % colors.length]} />
              ))}
            </Bar>
          </BarChart>
        </ResponsiveContainer>
      </div>
    </div>
  );
}

import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import * as z from 'zod';
import { supabase } from '../../lib/supabase';
import { useAuth } from '../../hooks/useAuth';
import type { Sube, Kayit } from '../../types';
import { Loader2, Plus, Save, CheckCircle2, X } from 'lucide-react';
import { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';

const subeler: Sube[] = ['MERKEZ', 'ANKARA', 'BURSA', 'BAYRAMPAŞA', 'MODOKO', 'İZMİR', 'MALZEME'];

const formSchema = z.object({
  tarih: z.string(),
  musteri_adi: z.string().min(2, 'Müşteri adı en az 2 karakter olmalıdır'),
  banka: z.string(),
  cekim_subesi: z.string(),
  tutar: z.number().min(1, 'Tutar 0 dan büyük olmalıdır'),
  taksit: z.number().min(1).max(24),
  notlar: z.string().optional(),
});

type FormValues = z.infer<typeof formSchema>;

interface RecordFormProps {
  onSuccess?: () => void;
  initialData?: Kayit | null;
  onCancel?: () => void;
  isRequest?: boolean;
}

export default function RecordForm({ onSuccess, initialData, onCancel, isRequest }: RecordFormProps) {
  const { user } = useAuth();
  const [loading, setLoading] = useState(false);
  const [success, setSuccess] = useState(false);

  const isEditing = !!initialData;
  const role = user?.user_metadata?.role as string;
  const metadataSube = user?.user_metadata?.sube as Sube;
  const currentSube: Sube = isEditing ? (initialData.sube_adi as Sube) : ((role === 'admin' || !metadataSube) ? 'MERKEZ' : metadataSube);

  const { register, handleSubmit, reset, watch, setValue, formState: { errors } } = useForm<FormValues>({
    resolver: zodResolver(formSchema),
    defaultValues: {
      tarih: new Date().toISOString().split('T')[0],
      banka: 'NAKİT',
      cekim_subesi: currentSube,
      taksit: 1,
    }
  });

  const [loadingSettings, setLoadingSettings] = useState(false);
  const [availableInstallments, setAvailableInstallments] = useState<number[]>([1]);
  const [dynamicOdemeTurleri, setDynamicOdemeTurleri] = useState<string[]>([
    'NAKİT', 'HAVALE / EFT', 'ÇEK', 'SENET', 'AKBANK POS', 'GARANTİ POS', 
    'İŞ BANKASI POS', 'ZİRAAT BANKASI POS', 'YAPI KREDİ POS', 'HALKBANK POS', 
    'QNB FİNANSBANK POS', 'DENİZBANK POS'
  ]);

  const selectedBanka = watch('banka');
  const selectedTarih = watch('tarih');

  useEffect(() => {
    const fetchBanks = async () => {
      const sabitDefaults = [
        'NAKİT', 'HAVALE / EFT', 'ÇEK', 'SENET',
        'AKBANK POS', 'GARANTİ POS', 'İŞ BANKASI POS', 'ZİRAAT BANKASI POS',
        'YAPI KREDİ POS', 'HALKBANK POS', 'QNB FİNANSBANK POS', 'DENİZBANK POS'
      ];
      try {
        const { data } = await supabase.from('banka_ayarlari').select('banka_adi');
        if (data && data.length > 0) {
          const uniqueBanks = Array.from(new Set(data.map((b: { banka_adi: string }) => b.banka_adi)));
          const combined = Array.from(new Set([...sabitDefaults, ...uniqueBanks]));
          setDynamicOdemeTurleri(combined);
        } else {
          // RLS engeli veya boş tablo - sabit listeyi kullan
          setDynamicOdemeTurleri(sabitDefaults);
        }
      } catch {
        // Hata durumunda da sabit listeyi göster
        setDynamicOdemeTurleri(sabitDefaults);
      }
    };
    fetchBanks();
  }, []);

  useEffect(() => {
    const fetchBankSettings = async () => {
      if (!selectedBanka || !selectedBanka.includes('POS')) {
        setAvailableInstallments([1]);
        setValue('taksit', 1);
        return;
      }

      setLoadingSettings(true);
      try {
        // 1. Try to fetch the agreement active on the selected date
        let { data: bankSettings, error: fetchError } = await supabase
          .from('banka_ayarlari')
          .select('komisyon_oranlari')
          .eq('banka_adi', selectedBanka)
          .lte('baslangic_tarihi', selectedTarih)
          .or(`bitis_tarihi.is.null,bitis_tarihi.gte.${selectedTarih}`)
          .order('baslangic_tarihi', { ascending: false })
          .limit(1)
          .maybeSingle();

        if (fetchError) {
            console.error('Banka ayarları çekilirken hata (L100):', fetchError);
        }

        // 2. FALLBACK: If no active agreement found for that date, try to get the latest one anyway
        // This helps if the user entered a date outside the current agreement range or if there's a minor sync issue.
        if (!bankSettings) {
            const { data: latestSettings } = await supabase
                .from('banka_ayarlari')
                .select('komisyon_oranlari')
                .eq('banka_adi', selectedBanka)
                .order('baslangic_tarihi', { ascending: false })
                .limit(1)
                .maybeSingle();

            if (latestSettings) {
                bankSettings = latestSettings;
            }
        }

        if (bankSettings && bankSettings.komisyon_oranlari) {
          const rates = bankSettings.komisyon_oranlari;
          // Extract installment numbers from keys (e.g. "1", "2", "3" ...)
          const insts = Object.keys(rates)
            .map(k => parseInt(k))
            .sort((a, b) => a - b);

          setAvailableInstallments(insts.length > 0 ? insts : [1]);
        } else {
          // If still no settings, and it's a POS, log it (likely RLS or no data)
          console.warn(`${selectedBanka} için taksit ayarı bulunamadı. RLS yetkisi veya eksik tanımlama olabilir.`);
          setAvailableInstallments([1]);
        }
      } catch (err) {
        console.error('Banka ayarları fetch hatası (Catch):', err);
        setAvailableInstallments([1]);
      } finally {
        setLoadingSettings(false);
      }
    };

    fetchBankSettings();
  }, [selectedBanka, selectedTarih, setValue]);

  useEffect(() => {
    if (initialData) {
      reset({
        tarih: initialData.tarih,
        musteri_adi: initialData.musteri_adi,
        banka: initialData.banka,
        cekim_subesi: initialData.cekim_subesi,
        tutar: initialData.tutar,
        taksit: initialData.taksit,
        notlar: initialData.notlar || '',
      });
    }
  }, [initialData, reset]);

  const onSubmit = async (data: FormValues) => {
    setLoading(true);
    setSuccess(false);

    try {
      if (isEditing) {
        if (isRequest) {
          const { error } = await supabase.from('talepler').insert({
            kayit_id: initialData.id,
            tip: 'DUZENLEME',
            yeni_veri: data,
            sube_adi: currentSube,
            talep_eden_id: user?.id,
            durum: 'BEKLEMEDE'
          });
          if (error) throw error;
        } else {
          const { error } = await supabase
            .from('kayitlar')
            .update(data)
            .eq('id', initialData.id);
          if (error) throw error;
        }
      } else {
        const { error } = await supabase.from('kayitlar').insert({
          ...data,
          sube_adi: currentSube,
          user_id: user?.id,
        });
        if (error) throw error;
      }

      setSuccess(true);
      if (!isEditing) {
        reset({
          tarih: new Date().toISOString().split('T')[0],
          banka: 'NAKİT',
          cekim_subesi: currentSube,
          taksit: 1,
        });
      }

      if (onSuccess) onSuccess();

      // IF POS: Generate and Save Payment Schedule
      if (data.banka.includes('POS')) {
        try {
          // 1. Fetch Bank Settings (Agreement active on transaction date)
          let { data: bankSettings, error: bankError } = await supabase
            .from('banka_ayarlari')
            .select('*')
            .eq('banka_adi', data.banka)
            .lte('baslangic_tarihi', data.tarih)
            .or(`bitis_tarihi.is.null,bitis_tarihi.gte.${data.tarih}`)
            .order('baslangic_tarihi', { ascending: false })
            .limit(1)
            .maybeSingle();

          if (!bankSettings) {
            // FALLBACK for non-admin or missing agreement: Use a 0-commission default if record saving shouldn't be blocked
            console.warn('Geçerli bir banka anlaşması bulunamadı, 0 komisyon ile plan oluşturulmaya çalışılacak.');
            bankSettings = {
                banka_adi: data.banka,
                vade_gun: 30,
                komisyon_oranlari: { [data.taksit]: 0 }
            };
          }

          if (bankError) {
             console.error('Banka ayarları kontrol hatası:', bankError);
          }

          // 2. Fetch Holidays
          const { data: holidaysData, error: holidayError } = await supabase
            .from('tatil_gunleri')
            .select('tarih');

          if (holidayError) throw holidayError;
          const holidayList = (holidaysData || []).map(h => h.tarih);

          // 3. Generate Schedule
          const { generatePaymentSchedule } = await import('../../utils/paymentCalculator');
          const schedule = generatePaymentSchedule(data, bankSettings as any, holidayList);

          // 4. Save to Database (First find the record ID if it's new)
          let finalRecordId = isEditing ? initialData.id : null;

          if (!isEditing) {
            // Get the ID of the record just inserted
            const { data: newRecord, error: fetchError } = await supabase
              .from('kayitlar')
              .select('id')
              .eq('user_id', user?.id)
              .order('created_at', { ascending: false })
              .limit(1)
              .single();
            if (!fetchError) finalRecordId = newRecord.id;
          }

          if (finalRecordId) {
            // Delete old schedule if editing
            if (isEditing) {
              await supabase.from('odeme_plani').delete().eq('kayit_id', finalRecordId);
            }

            // Insert new schedule
            const scheduleToInsert = schedule.map(s => ({
              kayit_id: finalRecordId,
              taksit_no: s.taksit_no,
              planlanan_tarih: s.planlanan_tarih,
              net_tutar: s.net_tutar,
              komisyon_tutar: s.komisyon_tutar,
              ana_tutar: s.ana_tutar,
              durum: 'BEKLEMEDE'
            }));

            await supabase.from('odeme_plani').insert(scheduleToInsert);
          }
        } catch (scheduleErr) {
          console.error('Payment schedule generation failed:', scheduleErr);
        }
      }

      setTimeout(() => setSuccess(false), 2000);
    } catch (error: any) {
      console.error('Error saving record:', error);
      alert('Kayıt kaydedilirken bir hata oluştu: ' + error.message);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className={`${isEditing ? '' : 'glassmorphism p-4 rounded-xl shadow-lg'} relative overflow-hidden transition-all text-foreground`}>
      <div className="flex items-center justify-between mb-3">
        <div className="flex items-center gap-2">
          <div className={`w-8 h-8 ${isEditing ? 'bg-blue-500/20' : 'bg-primary/20'} rounded-full flex items-center justify-center`}>
            {isEditing ? <Save className="text-blue-500 w-4 h-4" /> : <Plus className="text-primary w-5 h-5" />}
          </div>
          <h2 className="text-base font-bold leading-none">
            {isEditing ? (isRequest ? 'Düzenleme Talebi Oluştur' : 'Kaydı Düzenle') : 'Yeni Kayıt Girişi'}
          </h2>
        </div>
        {onCancel && (
          <button onClick={onCancel} className="p-1 hover:bg-muted rounded-full transition-colors">
            <X className="w-5 h-5 text-muted-foreground" />
          </button>
        )}
      </div>

      <form onSubmit={handleSubmit(onSubmit)} className="space-y-3">
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-3">
          <div className="space-y-1">
            <label className="text-[10px] uppercase font-bold text-muted-foreground ml-1">İşlem Tarihi</label>
            <input
              type="date"
              {...register('tarih')}
              className="w-full bg-muted/50 border border-border/50 rounded-lg px-3 py-1.5 text-sm focus:ring-1 focus:ring-primary/50 outline-none transition-all"
            />
          </div>

          <div className="space-y-1 lg:col-span-2">
            <label className="text-[10px] uppercase font-bold text-muted-foreground ml-1">Müşteri / Cari Adı</label>
            <input
              type="text"
              placeholder="Müşteri adı..."
              {...register('musteri_adi')}
              className={`w-full bg-muted/50 border ${errors.musteri_adi ? 'border-destructive' : 'border-border/50'} rounded-lg px-3 py-1.5 text-sm focus:ring-1 focus:ring-primary/50 outline-none transition-all`}
            />
          </div>

          <div className="space-y-1">
            <label className="text-[10px] uppercase font-bold text-muted-foreground ml-1">Ödeme Türü</label>
            <select
              {...register('banka')}
              className="w-full bg-muted/50 border border-border/50 rounded-lg px-3 py-1.5 text-sm focus:ring-1 focus:ring-primary/50 outline-none transition-all appearance-none"
            >
              {dynamicOdemeTurleri.map(t => <option key={t} value={t}>{t}</option>)}
            </select>
          </div>

          <div className="space-y-1">
            <label className="text-[10px] uppercase font-bold text-muted-foreground ml-1">Çekim Şubesi</label>
            <select
              {...register('cekim_subesi')}
              className="w-full bg-muted/50 border border-border/50 rounded-lg px-3 py-1.5 text-sm focus:ring-1 focus:ring-primary/50 outline-none transition-all appearance-none"
            >
              {subeler.map(s => <option key={s} value={s}>{s}</option>)}
            </select>
          </div>

          <div className="space-y-1">
            <label className="text-[10px] uppercase font-bold text-muted-foreground ml-1">Tutar (TL)</label>
            <input
              type="number"
              step="0.01"
              placeholder="0.00"
              {...register('tutar', { valueAsNumber: true })}
              className={`w-full bg-muted/50 border ${errors.tutar ? 'border-destructive' : 'border-border/50'} rounded-lg px-3 py-1.5 text-sm font-bold focus:ring-1 focus:ring-primary/50 outline-none transition-all`}
            />
          </div>

          <div className="space-y-1">
            <label className="text-[10px] uppercase font-bold text-muted-foreground ml-1">Taksit</label>
            {(() => {
              const isPos = selectedBanka && selectedBanka.includes('POS');

              if (!isPos) {
                return (
                  <input
                    type="number"
                    disabled
                    placeholder="1"
                    {...register('taksit', { valueAsNumber: true })}
                    className="w-full bg-muted border border-border/50 rounded-lg px-3 py-1.5 text-sm outline-none opacity-50"
                  />
                );
              }

              // Loading state or options
              if (loadingSettings) {
                return (
                  <div className="w-full bg-muted/50 border border-border/50 rounded-lg px-3 py-1.5 text-sm flex items-center gap-2">
                    <Loader2 size={12} className="animate-spin text-primary" />
                    <span className="text-[10px] uppercase font-bold text-muted-foreground">Yükleniyor...</span>
                  </div>
                );
              }

              return (
                <select
                  {...register('taksit', { valueAsNumber: true })}
                  className="w-full bg-muted/50 border border-border/50 rounded-lg px-3 py-1.5 text-sm focus:ring-1 focus:ring-primary/50 outline-none transition-all appearance-none"
                >
                  {availableInstallments.map(i => (
                    <option key={i} value={i}>{i} Taksit</option>
                  ))}
                </select>
              );
            })()}
          </div>

          <div className="space-y-1 lg:col-span-2">
            <label className="text-[10px] uppercase font-bold text-muted-foreground ml-1">Açıklama</label>
            <input
              type="text"
              placeholder="Notlar..."
              {...register('notlar')}
              className="w-full bg-muted/50 border border-border/50 rounded-lg px-3 py-1.5 text-sm focus:ring-1 focus:ring-primary/50 outline-none transition-all"
            />
          </div>
        </div>

        <div className="pt-2 flex items-center justify-between gap-4">
          <AnimatePresence>
            {success && (
              <motion.div
                initial={{ opacity: 0, x: -10 }}
                animate={{ opacity: 1, x: 0 }}
                exit={{ opacity: 0, x: -10 }}
                className="flex items-center gap-1.5 text-green-500 text-xs font-bold"
              >
                <CheckCircle2 className="w-4 h-4" />
                Başarı ile {isEditing ? (isRequest ? 'talep iletildi' : 'güncellendi') : 'kaydedildi'}
              </motion.div>
            )}
          </AnimatePresence>

          <div className="ml-auto flex items-center gap-2">
            {onCancel && (
              <button
                type="button"
                onClick={onCancel}
                className="px-4 py-2 rounded-lg text-sm font-bold border border-border hover:bg-muted transition-all"
              >
                İptal
              </button>
            )}
            <button
              type="submit"
              disabled={loading}
              className={`flex items-center gap-2 px-6 py-2 rounded-lg text-sm font-bold shadow-lg transition-all active:scale-[0.98] disabled:opacity-50 ${isEditing ? (isRequest ? 'bg-orange-500 hover:bg-orange-600 shadow-orange-500/20' : 'bg-blue-500 hover:bg-blue-600 shadow-blue-500/20') : 'bg-primary hover:bg-primary/90 shadow-primary/20'} text-white`}
            >
              {loading ? <Loader2 className="w-4 h-4 animate-spin" /> : <Save className="w-4 h-4" />}
              {isEditing ? (isRequest ? 'Talebi İlet' : 'Güncelle') : 'Kaydet'}
            </button>
          </div>
        </div>
      </form>
    </div>
  );
}

import type { Kayit } from '../../types';
import { format } from 'date-fns';
import { tr } from 'date-fns/locale';
import { 
  ChevronUp, 
  ChevronDown, 
  ArrowUpDown, 
  Pencil, 
  Trash2, 
  Lock, 
  Clock 
} from 'lucide-react';
import { useState, useMemo, useEffect } from 'react';
import { useAuth } from '../../hooks/useAuth';
import { supabase } from '../../lib/supabase';

interface RecordsTableProps {
  records: Kayit[];
  loading: boolean;
  onRefresh?: () => void;
  onEdit?: (record: Kayit, isRequest: boolean) => void;
}

type SortKey = keyof Kayit;
type SortOrder = 'asc' | 'desc';

export default function RecordsTable({ records, loading, onRefresh, onEdit }: RecordsTableProps) {
  const { user } = useAuth();
  const [sortKey, setSortKey] = useState<SortKey>('tarih');
  const [sortOrder, setSortOrder] = useState<SortOrder>('desc');
  const [deletingId, setDeletingId] = useState<string | null>(null);
  const [pendingRequests, setPendingRequests] = useState<string[]>([]);

  const role = user?.user_metadata?.role as string;
  const sube = user?.user_metadata?.sube as string;

  useEffect(() => {
    fetchPendingRequests();
  }, [records]);

  const fetchPendingRequests = async () => {
    if (!records.length) return;
    try {
      const { data, error } = await supabase
        .from('talepler')
        .select('kayit_id')
        .eq('durum', 'BEKLEMEDE');

      if (error) throw error;
      setPendingRequests(data?.map(r => r.kayit_id) || []);
    } catch (error) {
      console.error('Error fetching requests:', error);
    }
  };

  const canEditDirectly = () => {
    return role === 'admin';
  };

  const handleDelete = async (record: Kayit) => {
    const direct = canEditDirectly();

    if (direct) {
      if (!window.confirm(`${record.musteri_adi} isimli kaydı silmek istediğinize emin misiniz?`)) return;
      setDeletingId(record.id);
      try {
        const { error } = await supabase.from('kayitlar').delete().eq('id', record.id);
        if (error) throw error;
        if (onRefresh) onRefresh();
      } catch (error: any) {
        alert('Silme işlemi başarısız: ' + error.message);
      } finally {
        setDeletingId(null);
      }
    } else {
      if (!window.confirm(`Bu kayıt 3 günden eski olduğu için silme TALEBİ oluşturulacaktır. Onaylıyor musunuz?`)) return;
      try {
        const { error } = await supabase.from('talepler').insert({
          kayit_id: record.id,
          tip: 'SILME',
          sube_adi: sube,
          talep_eden_id: user?.id,
          durum: 'BEKLEMEDE'
        });
        if (error) throw error;
        alert('Silme talebi başarıyla iletildi. Admin onayından sonra silinecektir.');
        fetchPendingRequests();
      } catch (error: any) {
        alert('Talep oluşturulamadı: ' + error.message);
      }
    }
  };

  const handleSort = (key: SortKey) => {
    if (sortKey === key) {
      setSortOrder(sortOrder === 'asc' ? 'desc' : 'asc');
    } else {
      setSortKey(key);
      setSortOrder('asc');
    }
  };

  const sortedRecords = useMemo(() => {
    if (!records) return [];
    return [...records].sort((a, b) => {
      const aVal = a[sortKey];
      const bVal = b[sortKey];

      if (aVal === bVal) return 0;

      if (typeof aVal === 'number' && typeof bVal === 'number') {
        return sortOrder === 'asc' ? aVal - bVal : bVal - aVal;
      }

      const aStr = String(aVal).toLowerCase();
      const bStr = String(bVal).toLowerCase();

      return sortOrder === 'asc' 
        ? aStr.localeCompare(bStr, 'tr') 
        : bStr.localeCompare(aStr, 'tr');
    });
  }, [records, sortKey, sortOrder]);

  if (loading) {
    return (
      <div className="w-full h-64 flex items-center justify-center">
        <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-primary"></div>
      </div>
    );
  }

  if (!records || records.length === 0) {
    return (
      <div className="text-center py-12 glassmorphism rounded-2xl border border-dashed border-border/50">
        <div className="text-muted-foreground">Henüz kayıt bulunmamaktadır.</div>
      </div>
    );
  }

  const SortIcon = ({ column }: { column: SortKey }) => {
    if (sortKey !== column) return <ArrowUpDown className="w-3 h-3 opacity-20 group-hover:opacity-50" />;
    return sortOrder === 'asc' ? <ChevronUp className="w-3 h-3 text-primary transition-transform" /> : <ChevronDown className="w-3 h-3 text-primary transition-transform" />;
  };

  const Th = ({ column, label, align = 'left' }: { column: SortKey, label: string, align?: 'left' | 'right' | 'center' }) => (
    <th 
      className={`px-6 py-4 cursor-pointer hover:bg-muted/30 transition-colors group select-none ${align === 'right' ? 'text-right' : align === 'center' ? 'text-center' : 'text-left'}`}
      onClick={() => handleSort(column)}
    >
      <div className={`flex items-center gap-2 ${align === 'right' ? 'justify-end' : align === 'center' ? 'justify-center' : 'justify-start'}`}>
        <span className={`text-[10px] font-bold uppercase tracking-wider ${sortKey === column ? 'text-primary' : ''}`}>{label}</span>
        <SortIcon column={column} />
      </div>
    </th>
  );

  return (
    <div className="glassmorphism rounded-xl overflow-hidden shadow-xl border border-border/50 bg-card/30">
      <div className="overflow-x-auto">
        <table className="w-full text-left border-collapse min-w-[1000px]">
          <thead className="bg-muted/50 border-b border-border/50">
            <tr>
              <Th column="tarih" label="Tarih" />
              <Th column="sube_adi" label="Şube" />
              <Th column="musteri_adi" label="Müşteri" />
              <Th column="banka" label="Ödeme Türü" />
              <Th column="cekim_subesi" label="Çekim Şubesi" />
              <Th column="taksit" label="Taksit" align="right" />
              <Th column="tutar" label="Tutar (TL)" align="right" />
              <th className="px-6 py-4 text-center text-[10px] uppercase font-bold tracking-wider text-muted-foreground">İşlem</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-border/20">
            {sortedRecords.map((record) => {
              const direct = canEditDirectly();
              const isPending = pendingRequests.includes(record.id);

              return (
                <tr 
                  key={record.id} 
                  className={`hover:bg-primary/5 transition-colors group ${!direct ? 'text-foreground/70' : ''}`}
                >
                  <td className="px-6 py-4 text-sm font-medium">
                    {format(new Date(record.tarih), 'dd MMM yyyy', { locale: tr })}
                  </td>
                  <td className="px-6 py-4">
                    <span className="text-[10px] font-bold uppercase py-0.5 px-2 rounded-md bg-primary/10 text-primary border border-primary/20">
                      {record.sube_adi}
                    </span>
                  </td>
                  <td className="px-6 py-4 text-sm text-foreground/80 truncate max-w-[200px]">
                    {record.musteri_adi}
                  </td>
                  <td className="px-6 py-4 text-sm text-muted-foreground">
                    {record.banka}
                  </td>
                  <td className="px-6 py-4 text-sm text-muted-foreground">
                    {record.cekim_subesi}
                  </td>
                  <td className="px-6 py-4 text-sm text-right font-mono font-bold">
                    {record.taksit}
                  </td>
                  <td className="px-6 py-4 text-right">
                    <span className="text-sm font-bold font-mono text-foreground">
                      {new Intl.NumberFormat('tr-TR', { style: 'currency', currency: 'TRY' }).format(record.tutar).replace('₺', '')}
                    </span>
                  </td>
                  <td className="px-6 py-4">
                    <div className="flex items-center justify-center gap-2">
                      {isPending ? (
                        <div 
                          className="flex items-center gap-1.5 text-orange-500 bg-orange-500/10 px-2 py-1 rounded-md border border-orange-500/20 cursor-help"
                          title="Bu kayıt için bekleyen bir onay talebi bulunmaktadır."
                        >
                          <Clock className="w-3.5 h-3.5 animate-pulse" />
                          <span className="text-[10px] font-bold tracking-tight">BEKLEMEDE</span>
                        </div>
                      ) : (
                        <>
                          <button 
                            onClick={() => onEdit && onEdit(record, !direct)}
                            className={`p-1.5 rounded-lg transition-colors ${direct ? 'text-blue-500 hover:bg-blue-500/10' : 'text-orange-500 hover:bg-orange-500/10'}`}
                            title={direct ? 'Düzenle' : 'Düzenleme Talebi Gönder'}
                          >
                            {direct ? <Pencil className="w-4 h-4" /> : <Lock className="w-4 h-4" />}
                          </button>
                          <button 
                            onClick={() => handleDelete(record)}
                            disabled={deletingId === record.id}
                            className={`p-1.5 rounded-lg text-destructive hover:bg-destructive/10 transition-colors ${deletingId === record.id ? 'animate-pulse' : ''}`}
                            title={direct ? 'Sil' : 'Silme Talebi Gönder'}
                          >
                            <Trash2 className="w-4 h-4" />
                          </button>
                        </>
                      )}
                    </div>
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>
    </div>
  );
}

import type { Kayit } from '../../types';
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip, Legend } from 'recharts';

interface TaksitChartProps {
  records: Kayit[];
}

export default function TaksitChart({ records }: TaksitChartProps) {
  // Group by installment tiers
  const dataMap = records.reduce((acc, record) => {
    const taksit = Number(record.taksit);
    let category = '';

    if (taksit === 1) category = 'Tek Çekim';
    else if (taksit <= 6) category = '2-6 Taksit';
    else if (taksit <= 12) category = '7-12 Taksit';
    else category = '12+ Taksit';

    acc[category] = (acc[category] || 0) + 1;
    acc[`${category}_total`] = (acc[`${category}_total`] || 0) + Number(record.tutar);
    return acc;
  }, {} as Record<string, number>);

  const data = [
    { name: 'Tek Çekim', value: dataMap['Tek Çekim'] || 0, total: dataMap['Tek Çekim_total'] || 0 },
    { name: '2-6 Taksit', value: dataMap['2-6 Taksit'] || 0, total: dataMap['2-6 Taksit_total'] || 0 },
    { name: '7-12 Taksit', value: dataMap['7-12 Taksit'] || 0, total: dataMap['7-12 Taksit_total'] || 0 },
    { name: '12+ Taksit', value: dataMap['12+ Taksit'] || 0, total: dataMap['12+ Taksit_total'] || 0 },
  ].filter(d => d.value > 0);

  const COLORS = ['#6366f1', '#10b981', '#f59e0b', '#ef4444'];

  return (
    <div className="glassmorphism p-6 rounded-2xl shadow-lg border border-border/50 h-[450px] flex flex-col">
      <div className="mb-4">
        <h3 className="text-lg font-bold text-foreground">Taksit Analizi</h3>
        <p className="text-xs text-muted-foreground mt-1">İşlem tutarlarının taksit oranlarına göre dağılımı.</p>
      </div>

      <div className="flex-1 w-full min-h-[300px]">
        <ResponsiveContainer width="99%" height="100%" minHeight={300}>
          <PieChart>
            <Pie
              data={data}
              cx="50%"
              cy="50%"
              innerRadius={60}
              outerRadius={100}
              paddingAngle={5}
              dataKey="value"
            >
              {data.map((_, index) => (
                <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
              ))}
            </Pie>
            <Tooltip
              contentStyle={{
                backgroundColor: 'rgba(15, 23, 42, 0.9)',
                border: '1px solid rgba(255,255,255,0.1)',
                borderRadius: '12px',
                color: '#fff'
              }}
              formatter={(value: any, name: any, props: any) => [
                `${value} İşlem (${new Intl.NumberFormat('tr-TR').format(Number(props.payload.total))} TL)`,
                name
              ]}
            />
            <Legend
              verticalAlign="bottom"
              height={36}
              content={({ payload }) => (
                <div className="flex flex-wrap justify-center gap-4 mt-4">
                  {payload?.map((entry: any, index: number) => (
                    <div key={`legend-${index}`} className="flex items-center gap-2">
                      <div className="w-3 h-3 rounded-full" style={{ backgroundColor: entry.color }} />
                      <span className="text-xs text-muted-foreground">{entry.value}</span>
                    </div>
                  ))}
                </div>
              )}
            />
          </PieChart>
        </ResponsiveContainer>
      </div>
    </div>
  );
}

import React, { createContext, useContext, useEffect, useState } from 'react';
import { supabase } from '../lib/supabase';
import type { User, Session } from '@supabase/supabase-js';

interface AuthContextType {
  user: User | null;
  session: Session | null;
  loading: boolean;
  signOut: () => Promise<void>;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

export const AuthProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [user, setUser] = useState<User | null>(null);
  const [session, setSession] = useState<Session | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    // Get initial session
    supabase.auth.getSession().then(({ data: { session } }) => {
      setSession(session);
      setUser(session?.user ?? null);
      setLoading(false);
    });

    // Listen for auth changes
    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      setSession(session);
      setUser(session?.user ?? null);
      setLoading(false);
    });

    return () => {
      subscription.unsubscribe();
    };
  }, []);

  const signOut = async () => {
    await supabase.auth.signOut();
  };

  return (
    <AuthContext.Provider value={{ user, session, loading, signOut }}>
      {children}
    </AuthContext.Provider>
  );
};

export const useAuth = () => {
  const context = useContext(AuthContext);
  if (context === undefined) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
};

import { useEffect, useState, useMemo } from 'react';
import { supabase } from '../lib/supabase';
